const sender = $('CF').first().json.sender;
const admin = $('CF').first().json.admin;
var data = [
  {
    timestamp: sender.timestamp,
    website: admin.website,
    name: sender.name,
    email: sender.email,
    phone: sender.phone,
    subject: sender.subject,
    message: sender.msg,
    generated_response: 'https://docs.google.com/document/d/' + $input.first().json.documentId + '/edit',
  }
]

return data;

const formattedDateTime = new Date().toLocaleString('en-MY', {
  timeZone: 'Asia/Kuala_Lumpur',
  hour12: false,
});

// DO NOT CHANGE THIS (UNLESS YOU ARE ADDING NEW FIELDS)
const init_val = {
  sender: {
    timestamp: "",
    name: "[your-name]",
    email: "[your-email]",
    subject: "[your-subject]",
    phone: "[your-phone]", // default cf7 template doesn't required phone number
    msg: "[your-message]"
  },
  admin: {
    website: "[_site_url]",
    email: "[_site_admin_email]"
  }
}

const items = {
  sender: {
    timestamp: formattedDateTime,
    name: $input.first().json.body.sender.name,
    email: $input.first().json.body.sender.email,
    subject: $input.first().json.body.sender.subject,
    phone: "[your-phone]", // change this to '$input.first().json.body.sender.phone' if your website have phone number field for user to fill in
    msg: $input.first().json.body.sender.msg
  },
  admin: {
    website: $input.first().json.body.admin.website,
    email: $input.first().json.body.admin.email
  }
};

for (const key in init_val.sender) {
  let val = items.sender[key];

  if (val == null || val === "" || val === init_val.sender[key]) {
    val = "N/A";
  }

  if (typeof val === "string") {
    val = val.trim();
  }

  items.sender[key] = val;
}

let data = $input.all();
console.log(data);

return [{ json: items }];
